-- Same-class deps are never removed (native spells are always safe)
local DEP_SPELLS = {
    [71] = 1,
    [768] = 11,
    [1120] = 9,
    [1784] = 4,
    [2457] = 1,
    [2458] = 1,
    [5487] = 11,
