-- SkillLine ID for the "Skill Jewels" spellbook tab
local SKILL_JEWELS_SKILLLINE = 900

local SOCKET_SLOTS = { 2, 3, 4, 6 }

-- Spell chain ranks: maps each gem spell to all other ranks in its chain
-- Built at load time from spell_ranks table to handle learn_low_rank=true
local RANK_CHAINS = {}
do
    local spellList = {}
    for _, chain in pairs(GEM_SPELLS) do
        for _, rank in ipairs(chain) do
            if type(rank) == "table" and rank.spell then
                spellList[#spellList + 1] = rank.spell
            end
        end
    end
    for _, entry in pairs(GEM_MULTI_SPELLS) do
        for _, spellId in ipairs(entry) do
            if type(spellId) == "number" then
                spellList[#spellList + 1] = spellId
            end
        end
    end
    for depSpell in pairs(DEP_SPELLS) do
        spellList[#spellList + 1] = depSpell
    end
    if #spellList > 0 then
        local idStr = table.concat(spellList, ",")
        local Q = WorldDBQuery(
            "SELECT sr1.spell_id, sr2.spell_id FROM spell_ranks sr1 " ..
            "JOIN spell_ranks sr2 ON sr1.first_spell_id = sr2.first_spell_id " ..
            "WHERE sr1.spell_id IN (" .. idStr .. ") " ..
            "AND sr2.spell_id != sr1.spell_id " ..
            "ORDER BY sr1.spell_id, sr2.`rank` DESC")
        if Q then
            repeat
                local gemSpell = Q:GetUInt32(0)
                local chainSpell = Q:GetUInt32(1)
                if not RANK_CHAINS[gemSpell] then
                    RANK_CHAINS[gemSpell] = {}
                end
                table.insert(RANK_CHAINS[gemSpell], chainSpell)
            until not Q:NextRow()
        end
    end
    local chainCount = 0
    for _ in pairs(RANK_CHAINS) do chainCount = chainCount + 1 end
    print("[SkillJewels] Built spell chain data for " .. chainCount .. " ranked spells.")
end

-- Per-player state tracking
-- lastGemState[guid] = string key of equipped enchantments (for skip optimization)
local pendingSync = {}
local lastGemState = {}

-- Debug logging (set to true to trace sync behavior)
local SYNC_DEBUG = false

-- =============================================================================
-- CORE LOGIC
-- =============================================================================

local function IsSkillGem(enchantId)
    return GEM_SPELLS[enchantId] or GEM_MULTI_SPELLS[enchantId]
end

local function GetGemClass(enchantId)
    local chain = GEM_SPELLS[enchantId]
    if chain then return chain.class end
    local multi = GEM_MULTI_SPELLS[enchantId]
    if multi then return multi.class end
    return 0
end

local function GetActiveEnchantments(player)
    local active = {}
    for slot = 0, 18 do
        local item = player:GetEquippedItemBySlot(slot)
        if item then
            for _, sockSlot in ipairs(SOCKET_SLOTS) do
                local enchantId = item:GetEnchantmentId(sockSlot)
                if enchantId and enchantId > 0 and IsSkillGem(enchantId) then
                    active[enchantId] = true
                end
            end
        end
    end
    return active
end

-- Compute a string key from equipped enchantments for change detection
local function ComputeGemStateKey(activeEnchants)
    local ids = {}
    for enchantId in pairs(activeEnchants) do
        ids[#ids + 1] = enchantId
    end
    table.sort(ids)
    local parts = {}
    for i, id in ipairs(ids) do
        parts[i] = tostring(id)
    end
    return table.concat(parts, ",")
end

local function GetBestRank(chain, playerLevel)
    local best = nil
    for i, rank in ipairs(chain) do
        if type(rank) == "table" and rank.spell and playerLevel >= rank.level then
            best = rank.spell
        end
    end
    return best
end

local function SyncGemSpells(player, forceSync)
    local guid = player:GetGUIDLow()
    local playerClass = player:GetClass()
    local playerLevel = player:GetLevel()

    -- Scan equipped items for cross-class gem enchantments
    local activeEnchants = GetActiveEnchantments(player)

    -- State caching: skip if nothing changed (handles bag moves, repeated events)
    local stateKey = ComputeGemStateKey(activeEnchants)
    if SYNC_DEBUG then
        local enchCount = 0
        for _ in pairs(activeEnchants) do enchCount = enchCount + 1 end
        print(string.format("[SJ-DBG] SyncGemSpells: forceSync=%s, class=%d, enchants=%d, stateKey=[%s], lastKey=[%s]",
            tostring(forceSync), playerClass, enchCount, stateKey, tostring(lastGemState[guid])))
    end
    if not forceSync and lastGemState[guid] == stateKey then
        if SYNC_DEBUG then print("[SJ-DBG]   -> SKIPPED (cache hit)") end
        return
    end
    lastGemState[guid] = stateKey

    -- Build protected set: spells from currently equipped cross-class gems
    local protectedSpells = {}
    local protectedDeps = {}
    local sameClassBlocked = false
    for enchantId in pairs(activeEnchants) do
        local gemClass = GetGemClass(enchantId)
        if gemClass == playerClass then
            sameClassBlocked = true
        else
            local chain = GEM_SPELLS[enchantId]
            if chain then
                for i, rank in ipairs(chain) do
                    if type(rank) == "table" and rank.spell then
                        protectedSpells[rank.spell] = true
                    end
                end
            end
            local multi = GEM_MULTI_SPELLS[enchantId]
            if multi then
                for _, spellId in ipairs(multi) do
                    if type(spellId) == "number" then
                        protectedSpells[spellId] = true
                    end
                end
            end
            -- Mark dependency spells as protected
            local deps = GEM_DEPS[enchantId]
            if deps then
                for _, depChain in ipairs(deps) do
                    for _, rank in ipairs(depChain) do
                        if type(rank) == "table" and rank.spell then
                            protectedDeps[rank.spell] = true
                        end
                    end
                end
            end
        end
    end

    -- Merge dep protection into main protected set so ALL removal
    -- paths (GEM_SPELLS sweep, RANK_CHAINS cascade) respect deps
    for depSpell in pairs(protectedDeps) do
        protectedSpells[depSpell] = true
    end

    if sameClassBlocked then
        player:SendBroadcastMessage(
            "|cffffff00[SkillJewels]|r Skill jewels for your own class have no effect."
        )
    end

    -- REMOVAL PHASE: skip entirely on login (forceSync)
    -- On equip/unequip: scan ALL cross-class gem spells, remove unprotected
    local removedCount = 0
    if not forceSync then
        if SYNC_DEBUG then print("[SJ-DBG]   REMOVAL PHASE: scanning all gem spells...") end
        for enchantId, chain in pairs(GEM_SPELLS) do
            if chain.class ~= playerClass then
                for i, rank in ipairs(chain) do
                    if type(rank) == "table" and rank.spell then
                        local hasIt = player:HasSpell(rank.spell)
                        local isProtected = protectedSpells[rank.spell]
                        if hasIt then
                            if SYNC_DEBUG then
                                print(string.format("[SJ-DBG]     spell %d (ench %d, class %d): HAS=true, protected=%s -> %s",
                                    rank.spell, enchantId, chain.class, tostring(isProtected),
                                    isProtected and "KEEP" or "REMOVE"))
                            end
                            if not isProtected then
                                player:RemoveSpell(rank.spell)
                                removedCount = removedCount + 1
                                -- Remove auto-taught lower ranks (learn_low_rank=true)
                                local chainRanks = RANK_CHAINS[rank.spell]
                                if chainRanks then
                                    for _, crSpell in ipairs(chainRanks) do
                                        if player:HasSpell(crSpell) and not protectedSpells[crSpell] then
                                            if SYNC_DEBUG then
                                                print(string.format("[SJ-DBG]       chain-remove %d (auto-taught lower rank)", crSpell))
                                            end
                                            player:RemoveSpell(crSpell)
                                            removedCount = removedCount + 1
                                        end
                                    end
                                end
                            end
                        end
                    end
                end
            end
        end
        for enchantId, entry in pairs(GEM_MULTI_SPELLS) do
            if entry.class ~= playerClass then
                for _, spellId in ipairs(entry) do
                    if type(spellId) == "number" then
                        local hasIt = player:HasSpell(spellId)
                        local isProtected = protectedSpells[spellId]
                        if hasIt then
                            if SYNC_DEBUG then
                                print(string.format("[SJ-DBG]     multi-spell %d (ench %d, class %d): HAS=true, protected=%s -> %s",
                                    spellId, enchantId, entry.class, tostring(isProtected),
                                    isProtected and "KEEP" or "REMOVE"))
                            end
                            if not isProtected then
                                player:RemoveSpell(spellId)
                                removedCount = removedCount + 1
                                -- Remove auto-taught lower ranks
                                local chainRanks = RANK_CHAINS[spellId]
                                if chainRanks then
                                    for _, crSpell in ipairs(chainRanks) do
                                        if player:HasSpell(crSpell) and not protectedSpells[crSpell] then
                                            if SYNC_DEBUG then
                                                print(string.format("[SJ-DBG]       chain-remove %d (auto-taught lower rank)", crSpell))
                                            end
                                            player:RemoveSpell(crSpell)
                                            removedCount = removedCount + 1
                                        end
                                    end
                                end
                            end
                        end
                    end
                end
            end
        end
        -- Remove unneeded dependency spells (forms/stances)
        -- DEP_SPELLS[id] = owning class ID; skip if native to player
        for depSpell, depClass in pairs(DEP_SPELLS) do
            if depClass ~= playerClass and not protectedDeps[depSpell] and player:HasSpell(depSpell) then
                if SYNC_DEBUG then
                    print(string.format("[SJ-DBG]     DEP RemoveSpell(%d) (no longer needed)", depSpell))
                end
                player:RemoveSpell(depSpell)
                removedCount = removedCount + 1
                local chainRanks = RANK_CHAINS[depSpell]
                if chainRanks then
                    for _, crSpell in ipairs(chainRanks) do
                        if player:HasSpell(crSpell) and not protectedDeps[crSpell] then
                            if SYNC_DEBUG then
                                print(string.format("[SJ-DBG]       dep chain-remove %d", crSpell))
                            end
                            player:RemoveSpell(crSpell)
                            removedCount = removedCount + 1
                        end
                    end
                end
            end
        end
        if SYNC_DEBUG then print(string.format("[SJ-DBG]   REMOVAL PHASE done: removed %d spells", removedCount)) end
    else
        if SYNC_DEBUG then print("[SJ-DBG]   REMOVAL PHASE: SKIPPED (forceSync/login)") end
    end

    -- Grant Skill Jewels tab BEFORE teaching spells so client knows
    -- where to place them (must happen before LearnSpell calls)
    if SKILL_JEWELS_SKILLLINE then
        local hasCrossClass = false
        for enchantId in pairs(activeEnchants) do
            if GetGemClass(enchantId) ~= playerClass then
                hasCrossClass = true
                break
            end
        end
        if SYNC_DEBUG then
            print(string.format("[SJ-DBG]   SetSkill phase: hasCrossClass=%s", tostring(hasCrossClass)))
        end
        if hasCrossClass then
            player:SetSkill(SKILL_JEWELS_SKILLLINE, 0, 1, 1)
        end
    end

    -- ADD PHASE: teach spells from all equipped cross-class gems
    if SYNC_DEBUG then print("[SJ-DBG]   ADD PHASE: teaching from equipped gems...") end
    local addedCount = 0
    for enchantId in pairs(activeEnchants) do
        if GetGemClass(enchantId) ~= playerClass then
            local chain = GEM_SPELLS[enchantId]
            if chain then
                local best = GetBestRank(chain, playerLevel)
                if best and not player:HasSpell(best) then
                    if SYNC_DEBUG then
                        print(string.format("[SJ-DBG]     LearnSpell(%d) from ench %d", best, enchantId))
                    end
                    player:LearnSpell(best)
                    addedCount = addedCount + 1
                end
            end
            local multi = GEM_MULTI_SPELLS[enchantId]
            if multi then
                for _, spellId in ipairs(multi) do
                    if type(spellId) == "number" and not player:HasSpell(spellId) then
                        if SYNC_DEBUG then
                            print(string.format("[SJ-DBG]     LearnSpell(%d) multi from ench %d", spellId, enchantId))
                        end
                        player:LearnSpell(spellId)
                        addedCount = addedCount + 1
                    end
                end
            end
            -- Teach dependency spells (forms/stances)
            local deps = GEM_DEPS[enchantId]
            if deps then
                for _, depChain in ipairs(deps) do
                    local best = GetBestRank(depChain, playerLevel)
                    if best and not player:HasSpell(best) then
                        if SYNC_DEBUG then
                            print(string.format("[SJ-DBG]     DEP LearnSpell(%d) for ench %d", best, enchantId))
                        end
                        player:LearnSpell(best)
                        addedCount = addedCount + 1
                    end
                end
            end
        end
    end
    if SYNC_DEBUG then print(string.format("[SJ-DBG]   ADD PHASE done: added %d spells", addedCount)) end

end

local function DeferredSync(player)
    local guid = player:GetGUIDLow()
    if pendingSync[guid] then
        if SYNC_DEBUG then print("[SJ-DBG] DeferredSync: already pending, skipping") end
        return
    end
    if SYNC_DEBUG then print("[SJ-DBG] DeferredSync: scheduling sync in 500ms") end
    pendingSync[guid] = true
    player:RegisterEvent(function(eventId, delay, repeats, player)
        pendingSync[player:GetGUIDLow()] = nil
        if SYNC_DEBUG then print("[SJ-DBG] DeferredSync: timer fired, running SyncGemSpells") end
        SyncGemSpells(player)
    end, 500, 1)
end

