-- PACKET HOOKS (unequip detection)
-- =============================================================================

local RESYNC_OPCODES = {
    0x10A,  -- CMSG_AUTOEQUIP_ITEM
    0x10B,  -- CMSG_AUTOSTORE_BAG_ITEM
    0x10C,  -- CMSG_SWAP_ITEM
    0x10D,  -- CMSG_SWAP_INV_ITEM
    0x4D5,  -- CMSG_EQUIPMENT_SET_USE
}

for _, opcode in ipairs(RESYNC_OPCODES) do
    RegisterPacketEvent(opcode, 5, function(event, packet, player)
        if player then
            if SYNC_DEBUG then print(string.format("[SJ-DBG] Packet hook fired: opcode=0x%X", opcode)) end
            DeferredSync(player)
        end
    end)
end

-- =============================================================================
-- SOCKET HOOK (gem socketing with level + class enforcement)
-- =============================================================================

RegisterPacketEvent(0x347, 5, function(event, packet, player)
    if not player then return end

    local itemGuid = packet:ReadGUID()
    local gemGuids = { packet:ReadGUID(), packet:ReadGUID(), packet:ReadGUID() }

    local playerLevel = player:GetLevel()
    local playerClass = player:GetClass()
    for _, gemGuid in ipairs(gemGuids) do
        local gemItem = player:GetItemByGUID(gemGuid)
        if gemItem then
            local entry = gemItem:GetEntry()
            local enchantId = GEM_ITEMS[entry]
            if enchantId then
                -- Block same-class gems
                local gemClass = GetGemClass(enchantId)
                if gemClass == playerClass then
                    player:SendBroadcastMessage(
                        "|cffff0000[SkillJewels]|r You cannot socket skill jewels for your own class."
                    )
                    return false
                end
                -- Level check
                local chain = GEM_SPELLS[enchantId]
                if chain then
                    local minLevel = nil
                    for i, rank in ipairs(chain) do
                        if type(rank) == "table" and rank.level then
                            minLevel = rank.level
                            break
                        end
                    end
                    if minLevel and playerLevel < minLevel then
                        player:SendBroadcastMessage(
                            "|cffff0000[SkillJewels]|r You must be level "
                            .. minLevel .. " to socket this gem."
                        )
                        return false
                    end
                end
            end
        end
    end

    player:RegisterEvent(function(eventId, delay, repeats, player)
        SyncGemSpells(player)
    end, 500, 1)
end)

