local GEM_ITEM_LIST = {}
for itemEntry, _ in pairs(GEM_ITEMS) do
    table.insert(GEM_ITEM_LIST, itemEntry)
end

RegisterPlayerEvent(42, function(event, player, command)
    if command ~= "randomgem" then return end

    local entry = GEM_ITEM_LIST[math.random(1, #GEM_ITEM_LIST)]
    local item = player:AddItem(entry, 1)
    if item then
        player:SendBroadcastMessage(
            "|cff00ff00[SkillJewels]|r Added random gem: " .. item:GetName()
        )
    else
        player:SendBroadcastMessage(
            "|cffff0000[SkillJewels]|r Inventory full!"
        )
    end

    return false
end)

-- =============================================================================
-- CHAT COMMAND: .cleanspells
-- One-time cleanup: removes ALL cross-class gem spells that are not
-- from currently equipped gems. Use after testing to clear orphaned spells.
-- =============================================================================

RegisterPlayerEvent(42, function(event, player, command)
    if command ~= "cleanspells" then return end

    local playerClass = player:GetClass()
    local activeEnchants = GetActiveEnchantments(player)

    -- Build protected set from currently equipped cross-class gems
    local protectedSpells = {}
    local protectedDeps = {}
    for enchantId in pairs(activeEnchants) do
        if GetGemClass(enchantId) ~= playerClass then
            local chain = GEM_SPELLS[enchantId]
            if chain then
                for i, rank in ipairs(chain) do
                    if type(rank) == "table" and rank.spell then
                        protectedSpells[rank.spell] = true
                    end
                end
            end
            local multi = GEM_MULTI_SPELLS[enchantId]
            if multi then
                for _, spellId in ipairs(multi) do
                    if type(spellId) == "number" then
                        protectedSpells[spellId] = true
                    end
                end
            end
            local deps = GEM_DEPS[enchantId]
            if deps then
                for _, depChain in ipairs(deps) do
                    for _, rank in ipairs(depChain) do
                        if type(rank) == "table" and rank.spell then
                            protectedDeps[rank.spell] = true
                        end
                    end
                end
            end
        end
    end

    -- Merge dep protection into main set so GEM_SPELLS sweep
    -- and RANK_CHAINS cascade also respect dep protection
    for depSpell in pairs(protectedDeps) do
        protectedSpells[depSpell] = true
    end

    -- Remove all unprotected cross-class gem spells
    local removedCount = 0
    for enchantId, chain in pairs(GEM_SPELLS) do
        if chain.class ~= playerClass then
            for i, rank in ipairs(chain) do
                if type(rank) == "table" and rank.spell then
                    if not protectedSpells[rank.spell] and player:HasSpell(rank.spell) then
                        player:RemoveSpell(rank.spell)
                        removedCount = removedCount + 1
                        local chainRanks = RANK_CHAINS[rank.spell]
                        if chainRanks then
                            for _, crSpell in ipairs(chainRanks) do
                                if player:HasSpell(crSpell) and not protectedSpells[crSpell] then
                                    player:RemoveSpell(crSpell)
                                    removedCount = removedCount + 1
                                end
                            end
                        end
                    end
                end
            end
        end
    end
    for enchantId, entry in pairs(GEM_MULTI_SPELLS) do
        if entry.class ~= playerClass then
            for _, spellId in ipairs(entry) do
                if type(spellId) == "number" then
                    if not protectedSpells[spellId] and player:HasSpell(spellId) then
                        player:RemoveSpell(spellId)
                        removedCount = removedCount + 1
                        local chainRanks = RANK_CHAINS[spellId]
                        if chainRanks then
                            for _, crSpell in ipairs(chainRanks) do
                                if player:HasSpell(crSpell) and not protectedSpells[crSpell] then
                                    player:RemoveSpell(crSpell)
                                    removedCount = removedCount + 1
                                end
                            end
                        end
                    end
                end
            end
        end
    end
    -- Remove unneeded dependency spells (skip same-class: native spells are safe)
    for depSpell, depClass in pairs(DEP_SPELLS) do
        if depClass ~= playerClass and not protectedDeps[depSpell] and player:HasSpell(depSpell) then
            player:RemoveSpell(depSpell)
            removedCount = removedCount + 1
            local chainRanks = RANK_CHAINS[depSpell]
            if chainRanks then
                for _, crSpell in ipairs(chainRanks) do
                    if player:HasSpell(crSpell) and not protectedDeps[crSpell] then
                        player:RemoveSpell(crSpell)
                        removedCount = removedCount + 1
                    end
                end
            end
        end
    end

    player:SendBroadcastMessage(string.format(
        "|cff00ff00[SkillJewels]|r Cleaned up %d orphaned cross-class spells.", removedCount))
    return false
end)

-- =============================================================================
-- CHAT COMMAND: .dirtyspells
-- Teaches ALL cross-class gem spells at the best rank for the player's level.
-- Inverse of .cleanspells. Spells will be cleaned up on next sync event.
-- =============================================================================

RegisterPlayerEvent(42, function(event, player, command)
    if command ~= "dirtyspells" then return end

    local playerClass = player:GetClass()
    local playerLevel = player:GetLevel()
    local addedCount = 0

    -- Grant the spellbook tab so spells have somewhere to land
    if SKILL_JEWELS_SKILLLINE then
        player:SetSkill(SKILL_JEWELS_SKILLLINE, 0, 1, 1)
    end

    -- Teach best rank from every cross-class rank-chain gem
    for enchantId, chain in pairs(GEM_SPELLS) do
        if chain.class ~= playerClass then
            local best = GetBestRank(chain, playerLevel)
            if best and not player:HasSpell(best) then
                player:LearnSpell(best)
                addedCount = addedCount + 1
            end
            -- Teach dependency spells
            local deps = GEM_DEPS[enchantId]
            if deps then
                for _, depChain in ipairs(deps) do
                    local depBest = GetBestRank(depChain, playerLevel)
                    if depBest and not player:HasSpell(depBest) then
                        player:LearnSpell(depBest)
                        addedCount = addedCount + 1
                    end
                end
            end
        end
    end

    -- Teach all spells from every cross-class multi-spell gem
    for enchantId, entry in pairs(GEM_MULTI_SPELLS) do
        if entry.class ~= playerClass then
            for _, spellId in ipairs(entry) do
                if type(spellId) == "number" and not player:HasSpell(spellId) then
                    player:LearnSpell(spellId)
                    addedCount = addedCount + 1
                end
            end
        end
    end

    player:SendBroadcastMessage(string.format(
        "|cff00ff00[SkillJewels]|r Taught %d cross-class spells. These will be cleaned up on next equip/unequip.", addedCount))
    return false
end)

